// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // Helper to get weather emoji/icon based on condition
  const getWeatherIcon = (condition: string): string => {
    const cond = condition.toLowerCase();
    if (cond.includes('sunny') || cond.includes('clear')) return '☀️';
    if (cond.includes('cloudy') || cond.includes('overcast')) return '☁️';
    if (cond.includes('rainy') || cond.includes('rain')) return '🌧️';
    if (cond.includes('snow')) return '❄️';
    if (cond.includes('storm') || cond.includes('thunder')) return '⛈️';
    if (cond.includes('windy') || cond.includes('wind')) return '💨';
    return '🌤️'; // Default fallback
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main Weather Card */}
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* Header: City Name */}
            <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>

            {/* Temperature and Condition Row */}
            <Row align="center" gap="var(--ggui-spacing-4)">
              {/* Large Temperature Display */}
              <Stack align="center" gap="var(--ggui-spacing-2)">
                <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">
                   {props.temperature}°{props.unit || 'C'}
                </Text>
              </Stack>

              {/* Weather Icon and Condition */}
               <Stack align="center" gap="var(--ggui-spacing-2)">
                 <Text size="4xl" role="img" tabIndex={0} aria-label={`Current weather: ${props.condition}`}>{getWeatherIcon(props.condition)}</Text>
                <Text size="lg" variant="body" color="var(--ggui-color-onSurface)">{props.condition}</Text>
              </Stack>
            </Row>

            {/* Divider */}
            <Divider orientation="horizontal" margin="var(--ggui-spacing-3)" />

            {/* Humidity and Wind Speed Stats */}
             <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
               <Stack direction="vertical" gap="var(--ggui-spacing-6)">
                <Row gap="var(--ggui-spacing-6)" justify="start">
                  {/* Humidity Card */}
                  <Stack gap="var(--ggui-spacing-2)" align="center">
                    <Icon name="droplets" size={24} color="var(--ggui-color-primary-600)" aria-hidden="true" />
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                    <Text size="xl" weight="bold" color="var(--ggui-color-primary-700)">{props.humidity}%</Text>
                  </Stack>

                  {/* Wind Speed Card */}
                  <Stack gap="var(--ggui-spacing-2)" align="center">
                    <Icon name="wind" size={24} color="var(--ggui-color-primary-600)" aria-hidden="true" />
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                    <Text size="xl" weight="bold" color="var(--ggui-color-primary-700)">{props.windSpeed} m/s</Text>
                  </Stack>
                </Row>
               </Stack>
             </Box>
          </Stack>
        </Card>

        {/* 5-Day Forecast Strip */}
        {props.forecast && props.forecast.length > 0 ? (
          <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={4} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>

              {/* Forecast Items Row */}
              <Row gap="var(--ggui-spacing-3)" wrap>
                {props.forecast.map((dayForecast, index) => (
                   <Box
                     key={index}
                     padding="var(--ggui-spacing-3)"
                     background="var(--ggui-color-surfaceVariant)"
                     borderRadius="var(--ggui-shape-radius-md)"
                     style={{ flex: '1 1 auto', minWidth: '100px' }}
                  >
                    <Stack gap="var(--ggui-spacing-2)" align="center">
                      {/* Day Name */}
                      {dayForecast.day && (
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">{dayForecast.day}</Text>
                      )}

                      {/* Weather Icon/Emoji */}
                      {dayForecast.icon && (
                        <Text size="2xl" role="img" aria-label={`Weather: ${dayForecast.icon}`}>{dayForecast.icon}</Text>
                      )}

                      {/* High/Low Temps */}
                      <Stack gap="var(--ggui-spacing-1)" align="center">
                        {dayForecast.high !== undefined && (
                          <Text variant="body" weight="semibold" color="var(--ggui-color-primary-700)">{dayForecast.high}°{props.unit || 'C'}</Text>
                        )}
                        {dayForecast.low !== undefined && (
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{dayForecast.low}°{props.unit || 'C'}</Text>
                        )}
                      </Stack>
                    </Stack>
                  </Box>
                ))}
              </Row>
            </Stack>
          </Card>
        ) : (
          <Alert variant="info">No forecast available</Alert>
        )}
      </Stack>
    </Container>
  );
}

