// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation helpers
  const isValidEmail = useCallback((value: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  }, []);

  const isStep1Valid = useCallback((): boolean => {
    return name.trim().length > 0 && email.trim().length > 0 && isValidEmail(email);
  }, [name, email, isValidEmail]);

  const nameError = name === '' ? '' : '';
  const emailError = email === '' ? '' : !isValidEmail(email) ? 'Invalid email format' : '';

  // Step 1: Name and Email
  const renderStep1 = () => (
    <Stack gap="var(--ggui-spacing-4)" align="stretch">
      <Heading level={3}>Step 1: Your Information</Heading>
      <Input
        label="Name"
        placeholder="Enter your full name"
        value={name}
        onChange={setName}
        required
        error={name === '' ? 'Name is required' : ''}
      />
      <Input
        label="Email"
        type="email"
        placeholder="you@example.com"
        value={email}
        onChange={setEmail}
        required
        error={emailError || (email === '' ? 'Email is required' : '')}
      />
    </Stack>
  );

  // Step 2: Satisfaction Rating
  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label,
  }));

  const renderStep2 = () => (
    <Stack gap="var(--ggui-spacing-4)" align="stretch">
      <Heading level={3}>Step 2: Satisfaction Rating</Heading>
      <RadioGroup
        label="How satisfied are you?"
        value={satisfaction}
        onChange={setSatisfaction}
        options={satisfactionOptions}
        direction="horizontal"
      />
    </Stack>
  );

  // Step 3: Feature Interests
  const renderStep3 = () => (
    <Stack gap="var(--ggui-spacing-4)" align="stretch">
      <Heading level={3}>Step 3: Feature Interests</Heading>
      <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
        Which features interest you?
      </Text>
      <Stack gap="var(--ggui-spacing-3)" align="stretch">
        {props.featureOptions.map((option) => (
          <Checkbox
            key={option}
            label={option}
            checked={features.includes(option)}
            onChange={(checked) => {
              if (checked) {
                setFeatures([...features, option]);
              } else {
                setFeatures(features.filter((f) => f !== option));
              }
            }}
          />
        ))}
      </Stack>
    </Stack>
  );

  // Step 4: Comments
  const renderStep4 = () => (
    <Stack gap="var(--ggui-spacing-4)" align="stretch">
      <Heading level={3}>Step 4: Additional Comments</Heading>
      <TextArea
        label="Your comments"
        placeholder="Share any additional feedback..."
        value={comments}
        onChange={setComments}
        rows={6}
        maxLength={500}
        showCount
      />
    </Stack>
  );

  // Step 5: Review
  const renderStep5 = () => (
    <Stack gap="var(--ggui-spacing-4)" align="stretch">
      <Heading level={3}>Review Your Answers</Heading>
      <Card padding="var(--ggui-spacing-4)" shadow="sm">
        <Stack gap="var(--ggui-spacing-3)" align="stretch">
          <div>
            <Text variant="label">Name</Text>
            <Text variant="body">{name}</Text>
          </div>
          <Divider margin="var(--ggui-spacing-2)" />
          <div>
            <Text variant="label">Email</Text>
            <Text variant="body">{email}</Text>
          </div>
          <Divider margin="var(--ggui-spacing-2)" />
          <div>
            <Text variant="label">Satisfaction</Text>
            <Text variant="body">
              {satisfaction
                ? props.satisfactionLabels[parseInt(satisfaction) - 1]
                : 'Not selected'}
            </Text>
          </div>
          <Divider margin="var(--ggui-spacing-2)" />
          <div>
            <Text variant="label">Interested Features</Text>
            {features.length > 0 ? (
              <Stack gap="var(--ggui-spacing-2)" align="stretch">
                {features.map((feature) => (
                  <Text key={feature} variant="body">
                    • {feature}
                  </Text>
                ))}
              </Stack>
            ) : (
              <Text variant="body">None selected</Text>
            )}
          </div>
          <Divider margin="var(--ggui-spacing-2)" />
          <div>
            <Text variant="label">Comments</Text>
            <Text variant="body">{comments || '(None provided)'}</Text>
          </div>
        </Stack>
      </Card>
    </Stack>
  );

  const handleNext = () => {
    if (currentStep === 1 && !isStep1Valid()) return;
    if (currentStep < 5) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = () => {
    submit({
      name,
      email,
      satisfaction: parseInt(satisfaction),
      features,
      comments,
    });
  };

  const getStepContent = () => {
    switch (currentStep) {
      case 1:
        return renderStep1();
      case 2:
        return renderStep2();
      case 3:
        return renderStep3();
      case 4:
        return renderStep4();
      case 5:
        return renderStep5();
      default:
        return null;
    }
  };

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        {/* Header */}
        <div>
          <Heading level={1}>Multi-Step Survey</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
            Step {currentStep} of 5
          </Text>
        </div>

        {/* Progress Bar */}
        <Progress
          value={currentStep}
          max={5}
          variant="default"
          size="md"
          showLabel={false}
        />

        {/* Step Content */}
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          {getStepContent()}
        </Card>

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" justify="end">
            {currentStep === 5 && (
              <Button
                variant="ghost"
                onClick={handleBack}
              >
                Edit
              </Button>
            )}
            {currentStep === 5 ? (
              <Button
                variant="primary"
                onClick={handleSubmit}
              >
                Submit
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={currentStep === 1 && !isStep1Valid()}
              >
                Next
              </Button>
            )}
          </Stack>
        </Row>
      </Stack>
    </Container>
  );
}
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string; title?: string; priority?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // State for task board
  const [tasks, setTasks] = useState(props.tasks || []);
  const [addingTaskInColumn, setAddingTaskInColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTaskTitle, setEditingTaskTitle] = useState('');

  // Sync tasks from props and stream updates
  useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  useEffect(() => {
    if (taskChanged.latest?.task) {
      const updatedTask = taskChanged.latest.task;
      const action = taskChanged.latest.action;

      if (action === 'delete' && updatedTask.id) {
        setTasks(prev => prev.filter(t => t.id !== updatedTask.id));
      } else if (action === 'create' && updatedTask.id) {
        setTasks(prev => [...prev, updatedTask]);
      } else if ((action === 'move' || action === 'edit') && updatedTask.id) {
        setTasks(prev => prev.map(t => t.id === updatedTask.id ? updatedTask : t));
      }
    }
  }, [taskChanged.latest]);

  // Compute stats
  const totalTasks = useMemo(() => tasks.length, [tasks]);
  const completedTasks = useMemo(() => tasks.filter(t => t.column === 'done').length, [tasks]);

  // Get tasks by column
  const getTasksByColumn = useCallback((columnId: string) => {
    return tasks.filter(t => t.column === columnId);
  }, [tasks]);

  // Handle adding a new task
  const handleAddTask = useCallback((columnId: string) => {
    if (!newTaskTitle.trim()) return;

    const taskId = `task-${Date.now()}`;
    const newTask = {
      id: taskId,
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId,
    };

    setTasks(prev => [...prev, newTask]);
    taskUpdate({
      action: 'create',
      taskId,
      data: { column: columnId, title: newTaskTitle, priority: newTaskPriority },
    });

    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingTaskInColumn(null);
  }, [newTaskTitle, newTaskPriority, taskUpdate]);

  // Handle moving a task to another column
  const handleMoveTask = useCallback((taskId: string, targetColumn: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: targetColumn } : t));
    taskUpdate({
      action: 'move',
      taskId,
      data: { column: targetColumn },
    });
  }, [taskUpdate]);

  // Handle editing a task title
  // Handle editing a task title
  const handleSaveEditTask = useCallback((taskId: string, newTitle: string) => {
    if (!newTitle.trim()) return;
    const task = tasks.find(t => t.id === taskId);
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, title: newTitle } : t));
    taskUpdate({
      action: 'edit',
      taskId,
      data: { column: task?.column || 'todo', title: newTitle },
    });
    setEditingTaskId(null);
  }, [tasks, taskUpdate]);

  // Priority badge color mapping
  const getPriorityVariant = (priority?: string) => {
    switch (priority) {
      case 'high': return 'error';
      case 'medium': return 'warning';
      case 'low': return 'success';
      default: return 'default';
    }
  };

  // Get priority label
  const getPriorityLabel = (priority?: string) => {
    return (priority || 'medium').charAt(0).toUpperCase() + (priority || 'medium').slice(1);
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-lg)">
          <Row gap="var(--ggui-spacing-4)" align="center">
            <Heading level={3}>Task Board</Heading>
            <Spacer size="flex" />
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
              {completedTasks} of {totalTasks} tasks completed
            </Text>
            <Progress value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0} max={100} size="sm" />
          </Row>
        </Box>

        {/* Kanban Board */}
        <Row gap="var(--ggui-spacing-4)" align="start">
          {props.columns.map((column) => {
            const columnTasks = getTasksByColumn(column.id || '');
            const isAddingInThisColumn = addingTaskInColumn === column.id;

            return (
              <Box
                key={column.id}
                padding="var(--ggui-spacing-4)"
                background="var(--ggui-color-surface)"
                borderRadius="var(--ggui-shape-radius-lg)"
                style={{ flex: '1', minWidth: '300px' }}
              >
                <Stack gap="var(--ggui-spacing-4)">
                  {/* Column Header */}
                  <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
                    <Heading level={4}>{column.name}</Heading>
                    <Badge variant="default" size="sm">{columnTasks.length}</Badge>
                  </Row>

                  <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

                  {/* Task List */}
                  <Stack gap="var(--ggui-spacing-3)">
                    {columnTasks.map((task) => {
                      const isEditing = editingTaskId === task.id;
                      const otherColumns = props.columns.filter(c => c.id !== column.id);

                      return (
                        <Card
                          key={task.id}
                          padding="var(--ggui-spacing-3)"
                          shadow="sm"
                          as={Hoverable}
                          hoverStyle={{ boxShadow: 'var(--ggui-shape-shadow-md)' }}
                        >
                          <Stack gap="var(--ggui-spacing-2)">
                            {/* Task Title (Editable) */}
                            {isEditing ? (
                              <Stack gap="var(--ggui-spacing-2)">
                                <Input
