                                  >
                                    Save
                                  </Button>
                                  <Button
                                    variant="ghost"
                                    size="xs"
                                    onClick={() => setEditingTaskId(null)}
                                  >
                                    Cancel
                                  </Button>
                                </Row>
                              </Stack>
                            ) : (
                              <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
                                <Text
                                  variant="body"
                                  color="var(--ggui-color-onSurface)"
                                  as={Clickable}
                                  onClick={() => {
                                    setEditingTaskId(task.id || null);
                                    setEditingTaskTitle(task.title || '');
                                  }}
                                  style={{ flex: 1, cursor: 'pointer' }}
                                >
                                  {task.title || 'Untitled Task'}
                                </Text>
                                <Button
                                  variant="ghost"
                                  size="xs"
                                  onClick={() => {
                                    setEditingTaskId(task.id || null);
                                    setEditingTaskTitle(task.title || '');
                                  }}
                                  leftIcon={<Icon name="edit" size={14} />}
                                >
                                  Edit
                                </Button>
                              </Row>
