                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      variant="outline"
                      size="sm"
                      fullWidth
                      onClick={() => {
                        setAddingTaskInColumn(column.id || null);
                        setNewTaskTitle('');
                        setNewTaskPriority('medium');
                      }}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

