interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





export default function Component(props: Props) {
  // State for search and selected element
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const gridRef = useRef<HTMLDivElement>(null);
  const [focusedIndex, setFocusedIndex] = useState<number | null>(null);

  // Filter elements based on search query (case-insensitive)
  // Filter elements based on search query and selected category (case-insensitive)
  const filteredElements = useMemo(() => {
    let result = props.elements;

    if (searchQuery.trim()) {
      const query = searchQuery.toLowerCase();
      result = result.filter(el =>
        (el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query))
      );
    }

    if (selectedCategory) {
      result = result.filter(el => el.category?.toLowerCase() === selectedCategory.toLowerCase());
    }

    return result;
  }, [searchQuery, selectedCategory, props.elements]);

  // Get unique categories for legend (ordered by chemistry convention)
  const categories = useMemo(() => {
    const categorySet = new Set(props.elements.map(el => el.category).filter(Boolean));
    const categoryOrder = [
      'alkali metal', 'alkaline earth metal', 'transition metal',
      'lanthanide', 'actinide', 'post-transition metal',
      'nonmetal', 'reactive nonmetal', 'halogen', 'noble-gas',
      'metalloid', 'other nonmetal'
    ];
    return Array.from(categorySet).sort((a, b) => {
      const aIdx = categoryOrder.indexOf(a?.toLowerCase() || '');
      const bIdx = categoryOrder.indexOf(b?.toLowerCase() || '');
      if (aIdx === -1) return 1;
      if (bIdx === -1) return -1;
      return aIdx - bIdx;
    });
  }, [props.elements]);

  // Color mapping for categories
  // Color mapping for categories (using design system tokens)
  const getCategoryColor = useCallback((category?: string): string => {
    const colors: Record<string, string> = {
      'alkali metal': 'var(--ggui-color-success-200)',
      'alkaline earth metal': 'var(--ggui-color-success-100)',
      'transition metal': 'var(--ggui-color-primary-100)',
      'lanthanide': 'var(--ggui-color-primary-300)',
      'actinide': 'var(--ggui-color-primary-400)',
      'post-transition metal': 'var(--ggui-color-primary-200)',
      'nonmetal': 'var(--ggui-color-primary-200)',
      'reactive nonmetal': 'var(--ggui-color-warning-200)',
      'halogen': 'var(--ggui-color-error-200)',
      'noble-gas': 'var(--ggui-color-info-200)',
      'metalloid': 'var(--ggui-color-warning-100)',
    };
    return colors[category?.toLowerCase() || ''] || 'var(--ggui-color-surfaceVariant)';
  }, []);
return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Interactive periodic table with element details and search functionality
          </Text>
        </Stack>

        {/* Search Input */}
        <SearchField
          value={searchQuery}
          onChange={setSearchQuery}
          placeholder="Search by name or symbol (e.g., 'Hydrogen', 'H')"/>

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Category Legend</Text>
            <Row gap="var(--ggui-spacing-4)" wrap={true}>
              {categories.map(category => {
                const isSelected = selectedCategory?.toLowerCase() === category?.toLowerCase();
                return (
                  <Row
                    key={category}
                    as={Clickable}
                    onClick={() => setSelectedCategory(isSelected ? null : category)}
                    gap="var(--ggui-spacing-2)"
                    align="center"
                    style={{
                      cursor: 'pointer',
                      padding: 'var(--ggui-spacing-2)',
                      borderRadius: 'var(--ggui-shape-radius-md)',
                      border: isSelected ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outline)',
                      transition: 'all 200ms ease-in-out',
                    }}>
                    <Box
                      style={{
                        width: 'var(--ggui-spacing-5)',
                        height: 'var(--ggui-spacing-5)',
                        backgroundColor: getCategoryColor(category),
                        borderRadius: 'var(--ggui-shape-radius-sm)',
                        border: '1px solid var(--ggui-color-outline)',
                      }}
                      role="img"
                      aria-label={`${category} category color`}>
                    </Box>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      {category}
                    </Text>
                  </Row>
                );
              })}
            </Row>
          </Stack>
        </Card>


        {/* Periodic Table Grid */}
        <Box
          ref={gridRef}
          role="grid"
          aria-label="Periodic table of elements. Use arrow keys to navigate, Enter to select.">
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, 1fr)',
              gap: 'var(--ggui-spacing-2)',
              padding: 'var(--ggui-spacing-4)',
              backgroundColor: 'var(--ggui-color-surface)',
              borderRadius: 'var(--ggui-shape-radius-lg)',
              border: '1px solid var(--ggui-color-outline)',
            }}>
            {filteredElements.map((element, index) => {
              const isEmpty = !element.symbol;
              const isSelected = selectedElement?.symbol === element.symbol;
              const isFocused = focusedIndex === index;

              return (
                <Box
                  key={`${element.row}-${element.col}`}
                  style={{
                    gridRow: element.row,
                    gridColumn: element.col,
                  }}>
                  {!isEmpty ? (
                    <Card
                      as={Clickable}
                      onClick={() => setSelectedElement(element)}
                      onKeyDown={(e) => {
                        if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') {
                          e.preventDefault();
                          setFocusedIndex(Math.max(0, (focusedIndex ?? index) - 1));
                        } else if (e.key === 'ArrowRight' || e.key === 'ArrowDown') {
                          e.preventDefault();
                          setFocusedIndex(Math.min(filteredElements.length - 1, (focusedIndex ?? index) + 1));
                        }
                      }}
                      padding="var(--ggui-spacing-2)"
                      shadow={isSelected ? 'md' : isFocused ? 'sm' : 'sm'}
                      style={{
                        backgroundColor: getCategoryColor(element.category),
                        cursor: 'pointer',
                        border: isSelected
                          ? '2px solid var(--ggui-color-primary-600)'
                          : isFocused
                          ? '2px solid var(--ggui-color-primary-400)'
                          : '1px solid var(--ggui-color-outline)',
                        minHeight: 'calc(var(--ggui-spacing-4) * 5)',
                        display: 'flex',
                        flexDirection: 'column',
                        justifyContent: 'space-between',
                        transition: 'all 200ms ease-in-out',
                        transform: isFocused || isSelected ? 'scale(1.02)' : 'scale(1)',
                      }}
                      tabIndex={isFocused ? 0 : -1}
                      aria-label={`Element ${element.name} (symbol ${element.symbol}, atomic number ${element.atomicNumber})`}>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant)"
                        align="left">
                        {element.atomicNumber}
                      </Text>
                      <Text
                        variant="body"
                        weight="bold"
                        color="var(--ggui-color-onSurface)"
                        align="center"
                        size="2xl">
                        {element.symbol}
                      </Text>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant)"
                        align="center">
                        {element.atomicWeight?.toFixed(2)}
                      </Text>
                    </Card>
                  ) : null}
                </Box>
              );
            })}
          </Box>
        </Box>

        {/* Detail Panel */}
        {/* Detail Panel */}
        {selectedElement && selectedElement.symbol && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Row gap="var(--ggui-spacing-4)" align="start">
                <Stack gap="var(--ggui-spacing-2)" style={{ flex: 1 }}>
                  <Heading level={2}>{selectedElement.name}</Heading>
                  <Row gap="var(--ggui-spacing-2)" align="center">
                    <Badge variant="primary">{selectedElement.symbol}</Badge>
                    <Badge variant="secondary">{selectedElement.category}</Badge>
                  </Row>
                </Stack>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedElement(null)}
                  aria-label="Close element details">
                  Close
                </Button>
              </Row>


              <Divider margin="var(--ggui-spacing-3)" />

              <Row gap="var(--ggui-spacing-6)" wrap={true}>
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Atomic Number
                  </Text>
                  <Text variant="body" weight="semibold">
                    {selectedElement.atomicNumber}
                  </Text>
                </Stack>

                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Atomic Weight
                  </Text>
                  <Text variant="body" weight="semibold">
                    {selectedElement.atomicWeight?.toFixed(3)}
                  </Text>
                </Stack>

                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Category
                  </Text>
                  <Text variant="body" weight="semibold">
                    {selectedElement.category}
                  </Text>
                </Stack>

                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Position
                  </Text>
                  <Text variant="body" weight="semibold">
                    Row {selectedElement.row}, Column {selectedElement.col}
                  </Text>
                </Stack>
              </Row>
            </Stack>
          </Card>
        )}

        {/* Empty State */}

        {filteredElements.length === 0 && (
          <Card padding="var(--ggui-spacing-8)" shadow="sm">
            <Stack gap="var(--ggui-spacing-3)" align="center" justify="center">
              <Icon name="search" size={48} color="var(--ggui-color-onSurfaceVariant)" aria-label="Search icon" />
              <Heading level={3} color="var(--ggui-color-onSurfaceVariant)">
                No elements found
              </Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">
                Try adjusting your search query
              </Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart');

  // State
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Derived values
  const isOutOfStock = (props.product.stock ?? 0) === 0;
  const isLowStock = (props.product.stock ?? 0) > 0 && (props.product.stock ?? 0) <= 5;
  const stockStatus = isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock';
  const stockVariant = isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success';

  // Format price with currency
  const formattedPrice = useMemo(() => {
    if (props.product.price === undefined) return '';
    const currency = props.product.currency || 'USD';
    return new Intl.NumberFormat(undefined, {
      style: 'currency',
      currency: currency,
    }).format(props.product.price);
  }, [props.product.price, props.product.currency]);

  // Render star rating
  const renderStars = (rating: number | undefined) => {
    if (rating === undefined) return null;
    const stars = Array.from({ length: 5 }, (_, i) => i < Math.floor(rating) ? '★' : '☆');
    return (
      <Row gap="var(--ggui-spacing-1)" align="center">
        <Text variant="bodySmall">{stars.join('')}</Text>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{rating.toFixed(1)} ({props.product.reviewCount || 0} reviews)</Text>
      </Row>
    );
  };

  // Render specifications table
  const renderSpecifications = () => {
    if (!Array.isArray(props.product.specifications) || props.product.specifications.length === 0) {
      return <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available.</Text>;
    }
    const specs = props.product.specifications as Array<{ key?: string; value?: string }>;
    return (
      <Table
        columns={[
          { key: 'key', header: 'Specification' },
          { key: 'value', header: 'Value' },
        ]}
        data={specs}
        compact
      />
    );
  };

  // Render reviews list
  const renderReviews = () => {
    if (!Array.isArray(props.product.reviews) || props.product.reviews.length === 0) {
      return <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet.</Text>;
    }
    const reviews = props.product.reviews as Array<{ author?: string; rating?: number; text?: string; date?: string }>;
    return (
      <Stack gap="var(--ggui-spacing-4)">
        {reviews.map((review, idx) => (
          <Card key={idx} padding="var(--ggui-spacing-4)" shadow="sm">
            <Stack gap="var(--ggui-spacing-2)">
              <Row justify="between" align="center">
                <Text variant="label">{review.author || 'Anonymous'}</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{review.date}</Text>
              </Row>
              {review.rating !== undefined && <Text variant="caption">{Array.from({ length: 5 }, (_, i) => i < review.rating! ? '★' : '☆').join('')}</Text>}
              <Text variant="body">{review.text}</Text>
            </Stack>
          </Card>
        ))}
      </Stack>
    );
  };

  const handleAddToCart = () => {
    const productId = props.product.id || 'unknown';
    addToCart({ productId, quantity });
  };

  const tabItems = [
    { key: 'description', label: 'Description', content: <Text>{props.product.description || 'No description available.'}</Text> },
    { key: 'specifications', label: 'Specifications', content: renderSpecifications() },
    { key: 'reviews', label: 'Reviews', content: renderReviews() },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Top Section: Image & Basic Info */}
        <Row gap="var(--ggui-spacing-6)" align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            padding="var(--ggui-spacing-6)"
            background="var(--ggui-color-primary-50)"
            borderRadius="var(--ggui-shape-radius-lg)"
            style={{ minWidth: '300px', minHeight: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Heading level={3} color="var(--ggui-color-primary-700)" align="center">
              {props.product.name || 'Product Image'}
            </Heading>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '300px' }}>
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={2}>{props.product.name}</Heading>
              {renderStars(props.product.rating)}
              <Heading level={3} color="var(--ggui-color-primary-600)">{formattedPrice}</Heading>
            </Stack>

            {/* Stock Status */}
            <Badge variant={stockVariant}>{stockStatus}</Badge>
          </Stack>
        </Row>

        <Divider />

        {/* Middle Section: Tabs */}
        <Tabs
          items={tabItems}
          activeKey={activeTab}
          onChange={setActiveTab}
          variant="line"
          size="md"
        />

        <Divider />

        {/* Bottom Section: Quantity & Add to Cart */}
        <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center">
          <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
            <Text variant="label">Quantity:</Text>
            <Button
              size="sm"
              variant="outline"
              onClick={() => setQuantity(Math.max(1, quantity - 1))}
              disabled={quantity <= 1}
            >
              −
            </Button>
            <Input
              label=""
              type="number"
              value={String(quantity)}
              onChange={(val) => {
                const num = Math.min(props.product.stock ?? 1, Math.max(1, parseInt(val, 10) || 1));
                setQuantity(num);
              }}
              style={{ width: '60px' }}
            />
            <Button
              size="sm"
              variant="outline"
              onClick={() => setQuantity(Math.min(props.product.stock ?? 1, quantity + 1))}
              disabled={quantity >= (props.product.stock ?? 1)}
            >
              +
            </Button>
          </Stack>
          <Button
            variant="primary"
            size="lg"
            onClick={handleAddToCart}
            disabled={isOutOfStock}
          >
            Add to Cart
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}
}

