import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [displayMessages, setDisplayMessages] = useState(props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<Record<string, boolean>>({});
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    setTimeout(() => {
      messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 0);
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [displayMessages, scrollToBottom]);

  // Handle incoming messages from stream
  useEffect(() => {
    if (message.latest) {
      setDisplayMessages(prev => [...prev, message.latest]);
    }
  }, [message.latest]);

  // Handle typing indicator from stream
  useEffect(() => {
    if (typing.latest) {
      const sender = typing.latest.sender || 'Unknown';
      if (typing.latest.active) {
        setTypingUsers(prev => ({ ...prev, [sender]: true }));
      } else {
        setTypingUsers(prev => {
          const updated = { ...prev };
          delete updated[sender];
          return updated;
        });
      }
    }
  }, [typing.latest]);

  // Handle message send
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  // Handle Enter key in input
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender: string;
      messages: Array<{ text: string; timestamp: string }>;
      isCurrentUser: boolean;
    }> = [];

    for (const msg of displayMessages) {
      const sender = msg.sender || 'Unknown';
      const isCurrentUser = sender === props.currentUser;
      const text = msg.text || '';
      const timestamp = msg.timestamp || '';

      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === sender && lastGroup.isCurrentUser === isCurrentUser) {
        lastGroup.messages.push({ text, timestamp });
      } else {
        groups.push({
          sender,
          messages: [{ text, timestamp }],
          isCurrentUser,
        });
      }
    }

    return groups;
  }, [displayMessages, props.currentUser]);

  // Format timestamp
  const formatTime = (timestamp: string) => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" radius="lg" padding="var(--ggui-spacing-4)" border>
        <Stack gap="var(--ggui-spacing-4)" direction="vertical">
          {/* Header */}
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
              <Heading level={2}>{props.title}</Heading>
              <Badge variant="primary" size="sm">{props.participantCount} participants</Badge>
            </Stack>
            {/* Typing indicator in header */}
            {Object.keys(typingUsers).length > 0 && (
              <Stack gap="var(--ggui-spacing-1)" direction="horizontal" align="center" aria-live="polite" aria-label="User typing indicator">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" style={{ fontStyle: 'italic' }}>
                  {Object.keys(typingUsers).join(', ')} {Object.keys(typingUsers).length === 1 ? 'is' : 'are'} typing...
                </Text>
                <Spinner size={14} color="var(--ggui-color-primary-600)" />
              </Stack>
            )}
          </Row>

          <Divider margin="var(--ggui-spacing-2)" />

          {/* Message List Area */}
          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
            style={{
              height: 'clamp(300px, 60vh, 500px)',
              overflowY: 'auto',
              border: '1px solid var(--ggui-color-outlineVariant)',
            }}
            role="log"
            aria-label="Message history"
          >
            <Stack gap="var(--ggui-spacing-3)" direction="vertical">
              {groupedMessages.length === 0 ? (
                <Text
                  variant="bodySmall"
                  color="var(--ggui-color-onSurfaceVariant)"
                  align="center"
                >
                  No messages yet. Start a conversation!
                </Text>
              ) : (
                groupedMessages.map((group, groupIdx) => (
                  <Stack
                    key={groupIdx}
                    gap="var(--ggui-spacing-2)"
                    direction="vertical"
                    align={group.isCurrentUser ? 'end' : 'start'}
                    style={{ alignSelf: group.isCurrentUser ? 'flex-end' : 'flex-start' }}
                  >
                    {/* Sender name for non-current users */}
                    {!group.isCurrentUser && (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        {group.sender}
                      </Text>
                    )}
                    {/* Messages in this group */}
                    {group.messages.map((msg, msgIdx) => (
                      <Box
                        key={msgIdx}
                        as={Hoverable}
                        padding="var(--ggui-spacing-3)"
                        background={
                          group.isCurrentUser
                            ? 'var(--ggui-color-primary-600)'
                            : 'var(--ggui-color-surfaceVariant)'
                        }
                        borderRadius="var(--ggui-shape-radius-md)"
                        role="region"
                        aria-label={group.isCurrentUser ? 'Message from you' : `Message from ${group.sender}`}
                        hoverStyle={{ opacity: 0.85 }}
                      >
                        <Stack gap="var(--ggui-spacing-1)" direction="vertical">
                          <Text
                            variant="body"
                            color={
                              group.isCurrentUser
                                ? 'var(--ggui-color-onContainer)'
                                : 'var(--ggui-color-onSurface)'
                            }
                          >
                            {msg.text}
                          </Text>
                          <Text
                            variant="caption"
                            color={
                              group.isCurrentUser
                                ? 'var(--ggui-color-onContainer, rgba(255, 255, 255, 0.8))'
                                : 'var(--ggui-color-onSurfaceVariant)'
                            }
                          >
                            {formatTime(msg.timestamp)}
                          </Text>
                        </Stack>
                      </Box>
                    ))}
                  </Stack>
                ))
              )}

          {/* Input Area */}
          <Row gap="var(--ggui-spacing-2)" align="end">
            <Input
              label="Message"
              placeholder="Type your message here..."
              value={inputValue}
              onChange={setInputValue}
              onKeyDown={handleKeyDown}
            />
            <Button
              variant="primary"
              onClick={handleSendMessage}
              disabled={!inputValue.trim()}
              rightIcon={<Icon name="send" size={18} />}
            >
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

