import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State: track displayed stocks, merge price updates, manage flash animation per stock
  const [displayedStocks, setDisplayedStocks] = useState(props.stocks);
  const [lastUpdatedTime, setLastUpdatedTime] = useState(new Date());
  const [flashingSymbols, setFlashingSymbols] = useState<Set<string>>(new Set());
  const flashTimeoutRef = useRef<Record<string, NodeJS.Timeout>>({});

  // Merge price updates into displayed stocks whenever a new event arrives
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      if (update.symbol) {
        setDisplayedStocks((prev) =>
          prev.map((stock) =>
            stock.symbol === update.symbol
              ? { ...stock, price: update.price ?? stock.price, change: update.change ?? stock.change, changePercent: update.changePercent ?? stock.changePercent }
              : stock
          )
        );
        // Trigger flash animation on the updated stock
        setFlashingSymbols((prev) => new Set([...prev, update.symbol!]));
        if (flashTimeoutRef.current[update.symbol!]) {
          clearTimeout(flashTimeoutRef.current[update.symbol!]);
        }
        flashTimeoutRef.current[update.symbol!] = setTimeout(() => {
          setFlashingSymbols((prev) => {
            const next = new Set(prev);
            next.delete(update.symbol!);
            return next;
          });
          delete flashTimeoutRef.current[update.symbol!];
        }, 500);
        // Update the last updated timestamp
        setLastUpdatedTime(new Date());
      }
    }
  }, [priceUpdate.latest]);

  // Format price with 2 decimals
  const formatPrice = (price?: number) => {
    return price !== undefined ? `$${price.toFixed(2)}` : 'N/A';
  };

  // Determine color based on change
  const getChangeColor = (change?: number) => {
    if (change === undefined) return 'var(--ggui-color-onSurfaceVariant)';
    return change >= 0 ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
  };

  // Determine border color based on change
  const getChangeBorderColor = (change?: number) => {
    if (change === undefined) return 'var(--ggui-color-outline)';
    return change >= 0 ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';
  };

  // Get arrow icon based on change
  const getArrowIcon = (change?: number) => {
    if (change === undefined) return '─';
    return change >= 0 ? '▲' : '▼';
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with title and live updated timestamp */}
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1}>Market Watch</Heading>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Last Updated: {lastUpdatedTime.toLocaleTimeString()}
          </Text>
        </Stack>

        {/* Stock cards grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
            gap: 'var(--ggui-spacing-4)',
          }}
        >
          {displayedStocks.map((stock) => {
            const isFlashing = flashingSymbols.has(stock.symbol || '');
            const changeColor = getChangeColor(stock.change);
            const changeBorderColor = getChangeBorderColor(stock.change);
            const arrowIcon = getArrowIcon(stock.change);

            return (
              <Card
                key={stock.symbol}
                padding="var(--ggui-spacing-4)"
                shadow="md"
                style={{
                  borderColor: changeBorderColor,
                  borderWidth: '1px',
                  backgroundColor: isFlashing
                    ? 'rgba(59, 130, 246, 0.1)'
                    : 'var(--ggui-color-surface)',
                  transition: 'background-color 200ms ease-out',
                }}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Ticker symbol (large, bold) */}
                  <Heading level={3} color="var(--ggui-color-onSurface)" style={{ margin: 0 }}>
                    {stock.symbol || 'N/A'}
                  </Heading>

                  {/* Company name */}
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    {stock.name || 'Unknown'}
                  </Text>

                  {/* Current price */}
                  <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">
                    {formatPrice(stock.price)}
                  </Text>

                  {/* Change amount and percentage with color coding */}
                  <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                    <Text variant="label" color={changeColor}>
                      {stock.change !== undefined ? (stock.change >= 0 ? '+' : '') + stock.change.toFixed(2) : 'N/A'}
                    </Text>
                    <Text variant="label" color={changeColor}>
                      {arrowIcon}
                    </Text>
                    <Text variant="label" color={changeColor}>
                      {stock.changePercent !== undefined ? (stock.changePercent >= 0 ? '+' : '') + stock.changePercent.toFixed(2) + '%' : 'N/A'}
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </Box>
      </Stack>
    </Container>
  );
}
