type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // Wire hooks
  const complete = useAction<ActionCompletePayload>('complete');

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || (props.avatarOptions.length > 0 ? props.avatarOptions[0] : ''),
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  // Validation state
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Validation helpers
  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep1 = (): boolean => {
    const newErrors: Record<string, string> = {};
    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
    }
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!validateEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
    }
    if (!formData.avatar) {
      newErrors.avatar = 'Please select an avatar';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };
  const validateStep2 = (): boolean => {
    // Step 2 has no required fields, always valid
    setErrors({});
    return true;
  };

  // Handlers
  const handleInputChange = (field: string, value: string | boolean) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    setErrors(prev => ({ ...prev, [field]: '' }));
  };

  const handleNext = () => {
    if (currentStep === 1) {
      if (validateStep1()) {
        setCurrentStep(2);
      }
    } else if (currentStep === 2) {
      if (validateStep2()) {
        setCurrentStep(3);
      }
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setErrors({});
    }
  };

  const handleComplete = () => {
    complete({
      name: formData.name,
      email: formData.email,
      avatar: formData.avatar,
      role: formData.role,
      emailNotifications: formData.emailNotifications,
      theme: formData.theme,
    });
  };

  // Computed progress percentage
  const progressPercentage = (currentStep / 3) * 100;

  // Step 1 validation
  const isStep1Valid = formData.name.trim() && validateEmail(formData.email) && formData.avatar;

  // Step 2 validation
  const isStep2Valid = true;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
