            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">{currentStep === 1 ? 'Profile Setup' : currentStep === 2 ? 'Preferences' : 'Review'}</Text>
          </Row>
          <Progress value={progressPercentage} max={100} size="md" />
        </Stack>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Stack gap="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)">
              <Input
                label="Name"
                value={formData.name}
                onChange={(value) => handleInputChange('name', value)}
                placeholder="Enter your full name"
                required
                error={errors.name}
              />
              <Input
                label="Email"
                type="email"
                value={formData.email}
                onChange={(value) => handleInputChange('email', value)}
                placeholder="Enter your email address"
                required
                error={errors.email}
              />
            </Stack>

            {/* Avatar Selection */}
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Avatar <span style={{ color: 'var(--ggui-color-error-600)' }}>*</span></Text>
              <Row gap="var(--ggui-spacing-3)" wrap align="center">
                {props.avatarOptions.map((emoji) => (
                  <Card
                    key={emoji}
                    as={Clickable}
                    onClick={() => handleInputChange('avatar', emoji)}
                    padding="var(--ggui-spacing-3)"
                    shadow={formData.avatar === emoji ? 'md' : 'sm'}
                    border={formData.avatar === emoji}
                    style={{
