                    }}
                  >
                    <Text size="3xl">{emoji}</Text>
                  </Card>
                ))}
              </Row>
              {errors.avatar && <Text variant="caption" color="var(--ggui-color-error-600)">{errors.avatar}</Text>}
            </Stack>
          </Stack>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Stack gap="var(--ggui-spacing-6)">
            <Select
              label="Role"
              value={formData.role}
              onChange={(value) => handleInputChange('role', value)}
              options={props.roleOptions.map(role => ({ value: role, label: role }))}
              placeholder="Select your role"
              required
              error={errors.role}
            />
            <Stack gap="var(--ggui-spacing-2)">
              <Toggle
                label="Enable email notifications"
                checked={formData.emailNotifications}
                onChange={(checked) => handleInputChange('emailNotifications', checked)}
              />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Receive updates and important notifications via email</Text>
            </Stack>
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Theme Preference</Text>
              <Row gap="var(--ggui-spacing-4)">
                <Card
                  as={Clickable}
                  onClick={() => handleInputChange('theme', 'light')}
                  padding="var(--ggui-spacing-3)"
                  shadow={formData.theme === 'light' ? 'md' : 'sm'}
                  border={formData.theme === 'light'}
                  style={{
                    cursor: 'pointer',
                    flex: 1,
                    backgroundColor: formData.theme === 'light' ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                    borderColor: formData.theme === 'light' ? 'var(--ggui-color-primary-600)' : 'transparent',
                    textAlign: 'center',
                  }}
                >
                  <Icon name="sun" size={24} color="var(--ggui-color-primary-600)" />
                  <Text variant="label" style={{ marginTop: 'var(--ggui-spacing-2)' }}>Light</Text>
                </Card>
                <Card
                  as={Clickable}
                  onClick={() => handleInputChange('theme', 'dark')}
                  padding="var(--ggui-spacing-3)"
                  shadow={formData.theme === 'dark' ? 'md' : 'sm'}
                  border={formData.theme === 'dark'}
                  style={{
                    cursor: 'pointer',
                    flex: 1,
                    backgroundColor: formData.theme === 'dark' ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                    borderColor: formData.theme === 'dark' ? 'var(--ggui-color-primary-600)' : 'transparent',
                    textAlign: 'center',
                  }}
                >
                  <Icon name="moon" size={24} color="var(--ggui-color-primary-600)" />
                  <Text variant="label" style={{ marginTop: 'var(--ggui-spacing-2)' }}>Dark</Text>
                </Card>
              </Row>
            </Stack>
          </Stack>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Stack gap="var(--ggui-spacing-6)">
            <Card padding="var(--ggui-spacing-4)" shadow="md">
              <Stack gap="var(--ggui-spacing-4)">
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading level={4}>Profile Summary</Heading>
                </Stack>
                <Divider margin="var(--ggui-spacing-2)" />
                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                  <Text>{formData.name}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                  <Text>{formData.email}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Avatar</Text>
                  <Text size="xl">{formData.avatar}</Text>
                </Row>
                <Divider margin="var(--ggui-spacing-2)" />
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading level={4}>Preferences Summary</Heading>
                </Stack>
                <Divider margin="var(--ggui-spacing-2)" />
                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Role</Text>
                  <Text>{formData.role}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email Notifications</Text>
                  <Badge variant={formData.emailNotifications ? 'success' : 'default'}>{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Badge>
                </Row>
                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Theme</Text>
                  <Badge variant="primary">{formData.theme === 'light' ? '☀️ Light' : '🌙 Dark'}</Badge>
                </Row>
              </Stack>
            </Card>
          </Stack>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Go Back
          </Button>
          {currentStep < 3 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={currentStep === 1 ? !isStep1Valid : currentStep === 2 ? !isStep2Valid : false}
            >
              Next
            </Button>
          )}
          {currentStep === 3 && (
            <Button
              variant="primary"
              onClick={handleComplete}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>

}
